#include <avr/wdt.h>
#include <EEPROM.h>
extern uint8_t scheduler_tick(unsigned long);
extern int pid_heater_control(float,float,float,float,float,float,float*,float*);
typedef void(*TFn)();
struct TEntry{uint32_t per;uint32_t last;TFn fn;uint32_t mxL;};
static float sv=0;
static float ig=0,le=0;
static int pout=0;
void t_sensor(){sv=analogRead(A0)*5.0f/1023.0f;}
void t_control(){pout=pid_heater_control(2.5f,sv,0.05f,1.5f,0.1f,0.02f,&ig,&le);analogWrite(6,constrain(pout,0,255));}
void t_display(){Serial.print("V:");Serial.println(sv,3);}
void t_telem(){
  Serial.print("{\"t\":");Serial.print(millis());
  for(uint8_t i=0;i<4;i++){
    Serial.print(",\"l");Serial.print(i);Serial.print("\":");
    Serial.print(tasks[i].mxL);tasks[i].mxL=0;}
  Serial.println("}");}
TEntry tasks[]={{50,0,t_sensor,0},{100,0,t_control,0},{200,0,t_display,0},{500,0,t_telem,0}};
uint8_t ntasks=4;
void setup(){
  Serial.begin(115200);
  if(MCUSR&(1<<WDRF)){EEPROM.write(0,0xAB);}
  MCUSR=0;
  wdt_enable(WDTO_1S);
  pinMode(6,OUTPUT);}
void loop(){scheduler_tick(millis());}
